import{_ as a,o as s,c as n,a2 as e}from"./chunks/framework.BWuWLRhz.js";const i="/assets/cases/personal/ziwei-system/online-chart-form.png",p="/assets/cases/personal/ziwei-system/chart-interaction.png",r="/assets/cases/personal/ziwei-system/ai-interpretation.png",m=JSON.parse('{"title":"紫微斗数数据化解读系统","description":"","frontmatter":{},"headers":[],"relativePath":"projects/personal/ziwei-ai-system.md","filePath":"projects/personal/ziwei-ai-system.md"}'),l={name:"projects/personal/ziwei-ai-system.md"};function d(o,t,h,c,g,b){return s(),n("div",null,[...t[0]||(t[0]=[e('<h1 id="紫微斗数数据化解读系统" tabindex="-1">紫微斗数数据化解读系统 <a class="header-anchor" href="#紫微斗数数据化解读系统" aria-label="Permalink to &quot;紫微斗数数据化解读系统&quot;">​</a></h1><blockquote><p>紫微斗数数据化解读系统是我独立推进并已上线的个人系统项目。我把两年多传统文化学习、上百万字笔记、Obsidian 知识管理、规则算法化、Python 全栈开发和 AI 问答结合起来，做成了一套 <span class="text-highlight-blue">在线排盘、命盘交互、积分测算、AI 解读和命盘问答系统</span>。</p></blockquote><p>线上地址：<a href="https://ziweimodel.cn/" target="_blank" rel="noreferrer">ziweimodel.cn</a></p><div class="project-snapshot"><div><strong>已上线系统</strong><span>在线排盘、命盘交互、积分消耗、AI 解读、命盘问答</span></div><div><strong>2 年学习沉淀</strong><span>传统文化、紫微斗数、中医启发与个人长期笔记</span></div><div><strong>百万字笔记</strong><span>通过 Obsidian 组织为可结构化、可调用的知识资产</span></div><div><strong>全栈实践</strong><span>为完成系统学习 Python 全栈开发，并借助 AI 完成落地</span></div></div><h2 id="项目缘起" tabindex="-1">项目缘起 <a class="header-anchor" href="#项目缘起" aria-label="Permalink to &quot;项目缘起&quot;">​</a></h2><p>这个项目对我来说是一个人生阶段的重要作品。</p><p>前期我经历过神经炎症疾病，后来通过针灸和中医调理逐步恢复。在中医医生的引导和机缘下，我接触到台湾倪海厦，一开始只是想学习中医，但后来更吸引我的是命理和传统文化。因为自己曾被看准过，我对紫微斗数产生了很强的兴趣，之后持续学习了两年多，积累了大量课程笔记、书籍整理、盘例记录和个人理解。</p><p>随着学习深入，我发现紫微斗数背后有很多可拆解的结构：星曜、宫位、四化、三方四正、大限、流年、格局、权重、触发条件和综合判断。刚好我长期做数据产品，也习惯从对象、关系、口径、规则和验证链路去理解复杂系统，于是我开始思考：能不能把这些知识数据化，让解盘从经验表达走向 <span class="text-highlight">结构化、可计算、可交互、可持续迭代</span>。</p><h2 id="项目定位" tabindex="-1">项目定位 <a class="header-anchor" href="#项目定位" aria-label="Permalink to &quot;项目定位&quot;">​</a></h2><p>紫微斗数数据化解读系统的核心定位，是把传统知识体系转成一套可运行的系统。</p><p>它包含几层能力：</p><table tabindex="0"><thead><tr><th>层级</th><th>系统能力</th></tr></thead><tbody><tr><td>知识层</td><td>将学习笔记、术语、星曜、宫位、四化和盘例沉淀为知识库</td></tr><tr><td>规则层</td><td>将隐性解读经验拆成可计算、可匹配、可解释的规则结构</td></tr><tr><td>算法层</td><td>结合命盘结构、大限、流年、宫位关系和权重进行测算</td></tr><tr><td>产品层</td><td>支持在线排盘、命盘切换、解读生成、积分消耗和 AI 问答</td></tr><tr><td>迭代层</td><td>后续继续清洗知识库、优化算法权重和提升解读准确性</td></tr></tbody></table><p>这个系统对我的意义，是把“我学过的东西”变成“系统可以调用的东西”。它也让我更深地理解了数据资产的价值：知识如果只停留在笔记里，价值很难被放大；一旦被结构化、规则化、产品化，就可以进入真实交互和持续迭代。</p><h2 id="产品展示" tabindex="-1">产品展示 <a class="header-anchor" href="#产品展示" aria-label="Permalink to &quot;产品展示&quot;">​</a></h2><div class="case-image-grid"><figure><img src="'+i+'" alt="紫微斗数在线排盘页面"><figcaption><strong>在线排盘：用户输入出生信息生成个人命盘</strong><span>支持姓名/昵称、性别、阳历/阴历、出生日期、出生时辰和出生地点输入，生成个人紫微斗数命盘，作为后续解读和问答的基础。</span></figcaption></figure><figure><img src="'+p+'" alt="紫微命盘交互页面"><figcaption><strong>命盘交互：本命、大限、流年、小限联动查看</strong><span>排盘后，用户可以在底部选择大限、流年等时间维度，右侧切换解读模块，通过积分触发测算，形成命盘结构和解读内容之间的交互。</span></figcaption></figure><figure><img src="'+r+`" alt="紫微斗数 AI 解读结果页面"><figcaption><strong>AI 解读：基于命盘结构生成分模块解读</strong><span>系统围绕性格特质、核心优势、主要课题、人生主线、事业方向、财富模式、感情模式等模块生成解读，并支持命盘 AI 问答，围绕个人命盘继续互动。</span></figcaption></figure></div><h2 id="我的角色" tabindex="-1">我的角色 <a class="header-anchor" href="#我的角色" aria-label="Permalink to &quot;我的角色&quot;">​</a></h2><p>这是我的个人项目，我承担了从知识整理、产品设计、系统开发到上线迭代的完整工作。</p><table tabindex="0"><thead><tr><th>工作方向</th><th>我做了什么</th></tr></thead><tbody><tr><td>领域学习</td><td>持续学习紫微斗数和传统文化，沉淀上百万字笔记与盘例理解</td></tr><tr><td>知识管理</td><td>用 Obsidian 建立知识库，将分散内容组织为可维护的知识系统</td></tr><tr><td>数据结构</td><td>将星曜、宫位、四化、运限、格局和断语拆成结构化字段与规则</td></tr><tr><td>算法设计</td><td>将解盘思路转成可计算流程，包括命盘结构、权重、触发条件和解读模块</td></tr><tr><td>全栈开发</td><td>为完成系统学习 Python 全栈开发，搭建在线排盘、后端服务和前端展示</td></tr><tr><td>AI 协作</td><td>借助 AI 完成代码实现、结构整理和功能迭代，同时持续校验解读质量</td></tr><tr><td>上线运营</td><td>完成线上部署，支持用户注册、积分消耗、命盘测算和命盘 AI 问答</td></tr></tbody></table><p>这个项目最核心的地方，是它让我真正把“缺什么，就去学什么”变成了行动。因为想做系统，我去学 Python；因为想让知识可调用，我去整理规则；因为想让结果更可信，我去思考数据清洗、算法权重和准确性验证。</p><h2 id="系统架构" tabindex="-1">系统架构 <a class="header-anchor" href="#系统架构" aria-label="Permalink to &quot;系统架构&quot;">​</a></h2><p>系统整体可以概括为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统文化学习与笔记</span></span>
<span class="line"><span>  -&gt; Obsidian 知识库</span></span>
<span class="line"><span>  -&gt; 术语 / 星曜 / 宫位 / 四化 / 格局结构化</span></span>
<span class="line"><span>  -&gt; 规则与算法设计</span></span>
<span class="line"><span>  -&gt; 在线排盘与命盘交互</span></span>
<span class="line"><span>  -&gt; AI 解读与命盘问答</span></span>
<span class="line"><span>  -&gt; 用户反馈与持续迭代</span></span></code></pre></div><p>技术链路上，系统围绕排盘、命盘结构、规则匹配、AI 解读和用户积分展开。前端负责输入、命盘展示和交互；后端负责命盘生成、解读触发、积分扣减和结果管理；知识库和规则层负责给 AI 提供结构化上下文。</p><p>我希望 AI 在这里基于命盘结构、知识规则和上下文进行表达，避免自由发挥。当前版本已经能够完成从排盘到解读的完整闭环，但我也清楚看到：早期知识库给的数据过多、过泛，形成的 LLM Wiki 还不够精准，后续需要重新清洗和压缩，让系统更准确、更稳定。</p><h2 id="数据化解盘思路" tabindex="-1">数据化解盘思路 <a class="header-anchor" href="#数据化解盘思路" aria-label="Permalink to &quot;数据化解盘思路&quot;">​</a></h2><p>紫微斗数本身有很强的结构性。命盘可以被拆成一组可计算的关系：</p><ul><li>星曜落在哪个宫位。</li><li>宫位之间如何形成三方四正。</li><li>大限、流年、小限如何引动本命结构。</li><li>四化如何改变星曜性质和事件方向。</li><li>不同组合如何形成优势、课题、风险和人生主线。</li></ul><p>我做这个系统时，先把知识拆成可用的数据结构，再交给大模型组织表达。这样做的目标，是让系统输出尽量具备来源、结构和可复盘逻辑，减少泛化表达。</p><p>这也是我从数据产品经验中延续下来的方法：先建立 <span class="text-highlight-blue">稳定的数据资产</span>，再建立 <span class="text-highlight">可解释的输出链路</span>，最后通过准确性和长期反馈获得用户信任。</p><h2 id="当前成果" tabindex="-1">当前成果 <a class="header-anchor" href="#当前成果" aria-label="Permalink to &quot;当前成果&quot;">​</a></h2><ul><li>完成紫微斗数在线排盘系统上线，访问地址为 <a href="https://ziweimodel.cn/" target="_blank" rel="noreferrer">ziweimodel.cn</a>。</li><li>支持用户输入出生信息生成命盘，并进行本命、大限、流年、小限等维度切换。</li><li>支持通过积分触发命盘解读，形成可运营的测算机制。</li><li>支持命盘 AI 问答，用户可以围绕自己的命盘继续互动。</li><li>完成从 Obsidian 知识库、规则整理、算法设计到 Python 全栈开发的完整实践。</li><li>沉淀了传统文化知识工程、AI 辅助开发、产品上线和持续迭代经验。</li></ul><h2 id="当前问题与后续迭代" tabindex="-1">当前问题与后续迭代 <a class="header-anchor" href="#当前问题与后续迭代" aria-label="Permalink to &quot;当前问题与后续迭代&quot;">​</a></h2><p>这个项目目前已经上线，但我不会把它包装成“已经完美”。它还有很多需要继续打磨的地方：</p><table tabindex="0"><thead><tr><th>方向</th><th>后续计划</th></tr></thead><tbody><tr><td>UI 体验</td><td>当前界面可用，但视觉层级、信息密度、移动端体验还需要继续优化</td></tr><tr><td>知识清洗</td><td>早期笔记和 LLM Wiki 内容偏多、偏泛，需要重新筛选、压缩和标注来源</td></tr><tr><td>算法权重</td><td>命盘解读涉及多层关系，规则权重和触发逻辑还需要通过案例持续校验</td></tr><tr><td>准确性反馈</td><td>需要引入用户反馈和案例回收，让解读结果可以被持续验证</td></tr><tr><td>问答质量</td><td>命盘 AI 问答需要更强的上下文控制，避免生成泛化内容</td></tr></tbody></table><p>我希望它成为一个长期系统。未来会继续围绕数据清洗、规则优化、案例验证、用户反馈和报告生成做迭代。</p><h2 id="对我的影响" tabindex="-1">对我的影响 <a class="header-anchor" href="#对我的影响" aria-label="Permalink to &quot;对我的影响&quot;">​</a></h2><p>这个项目对我的影响很大。</p><p>它让我确认了一个方向：传统知识并不一定和现代技术相冲突。只要能找到合适的数据结构和产品形态，传统文化也可以被系统化、交互化、持续迭代。</p><p>它也让我更相信学习力和好奇心的重要性。很多能力来自真实问题的牵引：想做系统，就学开发；想让解读可信，就学数据结构；想让知识活起来，就学知识管理；想让用户能持续使用，就学产品运营。</p><p>统计学家 C. R. Rao 在《Statistics and Truth》前言中引用过一组话，我很喜欢它表达的思路：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>在终极的分析中，一切知识都是历史。</span></span>
<span class="line"><span>All knowledge is, in final analysis, history.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在抽象的意义下，一切科学都是数学。</span></span>
<span class="line"><span>All sciences are, in the abstract, mathematics.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在理性的世界里，所有的判断都是统计学。</span></span>
<span class="line"><span>All judgements are, in their rationale, statistics.</span></span></code></pre></div><p>这几句话和我做这个项目的感受非常接近：知识需要来源，科学需要结构，判断需要统计和验证。紫微斗数数据化解读系统对我来说，就是一次把个人经历、传统文化、知识管理、数据结构、AI 和工程能力连接起来的实践。</p>`,42)])])}const f=a(l,[["render",d]]);export{m as __pageData,f as default};
